#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, R;
        scanf("%d %d", &N, &R);
        int prev = -1;
        int dir = 0;
        for (int i = 0; i < N; i++) {
            int curr;
            scanf("%d", &curr);
            if (i == 0) {
                if (curr > R) dir = -1;
                else dir = 1;
            } else {
                if ((curr > R && dir == -1) || (curr < R && dir == 1)) {
                    printf("NO\n");
                    break;
                }
                if (i == N - 1) printf("YES\n");
            }
        }
    }
    return 0;
}

